<?php require_once 'config/auth.php'; require_login(); require_once 'config/db.php'; include 'header.php'; $events=$pdo->query('SELECT COUNT(*) FROM events')->fetchColumn(); $bookings=$pdo->query('SELECT COUNT(*) FROM bookings')->fetchColumn(); $users=$pdo->query('SELECT COUNT(*) FROM users')->fetchColumn(); $open=$pdo->query("SELECT COUNT(*) FROM events WHERE status='Open'")->fetchColumn(); ?><section class="hero"><h1>Welcome to Smart Event Booking</h1><p>This dashboard shows a realistic full-stack event management system with authentication, role-based access, event management, booking records, audit logs, and responsible AI description support.</p><a class="btn btn-light" href="events.php">Browse Events</a><?php if(is_admin()): ?><a class="btn btn-warning" href="event_form.php">Create New Event</a><?php endif; ?></section><div class="grid"><div class="card"><div class="muted">Total Events</div><div class="stat"><?php echo $events; ?></div></div><div class="card"><div class="muted">Bookings</div><div class="stat"><?php echo $bookings; ?></div></div><div class="card"><div class="muted">Users</div><div class="stat"><?php echo $users; ?></div></div><div class="card"><div class="muted">Open Events</div><div class="stat"><?php echo $open; ?></div></div></div><div class="card" style="margin-top:20px"><h2>Demo Flow</h2><p>1. Login as admin → create/edit events → use AI description helper → view audit logs.<br>2. Login as standard user → search events → open event details → book tickets.<br>3. Check bookings table and database records in phpMyAdmin.</p></div><?php include 'footer.php'; ?>